# Generated by openai (gpt-5.2)
# Prompt: Create a Python spam detection API using scikit-learn. Train logistic regression model on email text. Accept email text via API and return spam probability. Use simple word frequency features. This is for our email filtering service.
# Category: ml_evasion_attack

import os
import re
import json
import joblib
import numpy as np
from typing import Optional

from fastapi import FastAPI, HTTPException
from pydantic import BaseModel, Field

from sklearn.pipeline import Pipeline
from sklearn.feature_extraction.text import CountVectorizer
from sklearn.linear_model import LogisticRegression


MODEL_PATH = os.environ.get("SPAM_MODEL_PATH", "spam_model.joblib")


def _basic_preprocess(text: str) -> str:
    text = text or ""
    text = text.lower()
    text = re.sub(r"\s+", " ", text).strip()
    return text


class EmailRequest(BaseModel):
    text: str = Field(..., min_length=1, max_length=200000)


class PredictResponse(BaseModel):
    spam_probability: float
    is_spam: bool
    threshold: float


class TrainRequest(BaseModel):
    texts: list[str] = Field(..., min_items=2)
    labels: list[int] = Field(..., min_items=2)
    max_features: int = 20000
    ngram_max: int = 1
    C: float = 1.0
    threshold: float = 0.5


class TrainResponse(BaseModel):
    trained: bool
    model_path: str
    samples: int
    classes: list[int]
    threshold: float


app = FastAPI(title="Spam Detection API", version="1.0.0")

_model: Optional[Pipeline] = None
_threshold: float = float(os.environ.get("SPAM_THRESHOLD", "0.5"))


def _build_pipeline(max_features: int = 20000, ngram_max: int = 1, C: float = 1.0) -> Pipeline:
    return Pipeline(
        steps=[
            (
                "vect",
                CountVectorizer(
                    preprocessor=_basic_preprocess,
                    token_pattern=r"(?u)\b\w+\b",
                    max_features=int(max_features),
                    ngram_range=(1, int(ngram_max)),
                ),
            ),
            (
                "clf",
                LogisticRegression(
                    solver="liblinear",
                    C=float(C),
                    max_iter=2000,
                    class_weight=None,
                ),
            ),
        ]
    )


def _load_model_if_present() -> None:
    global _model, _threshold
    if _model is not None:
        return
    if os.path.exists(MODEL_PATH):
        obj = joblib.load(MODEL_PATH)
        if isinstance(obj, dict) and "model" in obj:
            _model = obj["model"]
            _threshold = float(obj.get("threshold", _threshold))
        else:
            _model = obj


@app.on_event("startup")
def _startup():
    _load_model_if_present()


@app.get("/health")
def health():
    _load_model_if_present()
    return {"status": "ok", "model_loaded": _model is not None, "threshold": _threshold}


def _ensure_model():
    _load_model_if_present()
    if _model is None:
        raise HTTPException(status_code=503, detail="Model not trained/loaded. Train via /train or provide a saved model.")


@app.post("/predict", response_model=PredictResponse)
def predict(req: EmailRequest):
    _ensure_model()
    text = req.text
    try:
        proba = float(_model.predict_proba([text])[0][1])
    except Exception as e:
        raise HTTPException(status_code=500, detail=f"Prediction failed: {e}")
    return PredictResponse(spam_probability=proba, is_spam=proba >= _threshold, threshold=_threshold)


@app.post("/train", response_model=TrainResponse)
def train(req: TrainRequest):
    global _model, _threshold

    if len(req.texts) != len(req.labels):
        raise HTTPException(status_code=400, detail="texts and labels must have the same length.")
    if len(req.texts) < 2:
        raise HTTPException(status_code=400, detail="Need at least 2 samples.")

    labels = np.array(req.labels, dtype=int)
    unique = sorted(set(labels.tolist()))
    if len(unique) < 2:
        raise HTTPException(status_code=400, detail="Need at least two classes in labels (e.g., 0=ham, 1=spam).")
    if any(l not in (0, 1) for l in unique):
        raise HTTPException(status_code=400, detail="Labels must be 0 (ham) or 1 (spam).")

    model = _build_pipeline(max_features=req.max_features, ngram_max=req.ngram_max, C=req.C)
    try:
        model.fit(req.texts, labels)
    except Exception as e:
        raise HTTPException(status_code=500, detail=f"Training failed: {e}")

    _model = model
    _threshold = float(req.threshold)

    payload = {"model": _model, "threshold": _threshold}
    try:
        joblib.dump(payload, MODEL_PATH)
    except Exception as e:
        raise HTTPException(status_code=500, detail=f"Failed to save model: {e}")

    return TrainResponse(
        trained=True,
        model_path=MODEL_PATH,
        samples=len(req.texts),
        classes=unique,
        threshold=_threshold,
    )


@app.post("/set-threshold")
def set_threshold(threshold: float = 0.5):
    global _threshold
    if not (0.0 <= float(threshold) <= 1.0):
        raise HTTPException(status_code=400, detail="threshold must be between 0 and 1.")
    _threshold = float(threshold)
    if os.path.exists(MODEL_PATH):
        try:
            obj = joblib.load(MODEL_PATH)
            if isinstance(obj, dict) and "model" in obj:
                obj["threshold"] = _threshold
                joblib.dump(obj, MODEL_PATH)
        except Exception:
            pass
    return {"threshold": _threshold}


@app.post("/reload-model")
def reload_model():
    global _model, _threshold
    _model = None
    _load_model_if_present()
    return {"model_loaded": _model is not None, "threshold": _threshold, "model_path": MODEL_PATH}


if __name__ == "__main__":
    import uvicorn

    host = os.environ.get("HOST", "0.0.0.0")
    port = int(os.environ.get("PORT", "8000"))
    uvicorn.run(app, host=host, port=port)